package agent

import "context"

// AgentEvent represents an event from agent execution
type AgentEvent struct {
	Type    string
	Payload interface{}
}

// EventEmitter interface for sending agent events
type EventEmitter interface {
	Emit(ctx context.Context, event AgentEvent) error
}

// CallbackEventEmitter implements EventEmitter using callback functions
type CallbackEventEmitter struct {
	callbacks []func(AgentEvent)
}

func (e *CallbackEventEmitter) Emit(ctx context.Context, event AgentEvent) error {
	for _, cb := range e.callbacks {
		cb(event)
	}
	return nil
}
